package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a file.
// It runs: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun output to jq input
	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdin pipe for jq: %w", err)
	}

	// Set jq stdout to write to the output file
	output, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer output.Close()

	jqCmd.Stdout = output
	jqCmd.Stderr = os.Stderr
	aliyunCmd.Stderr = os.Stderr

	// Start jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Connect aliyun stdout to jq stdin
	aliyunCmd.Stdout = jqStdin

	// Run aliyun command
	if err := aliyunCmd.Run(); err != nil {
		jqStdin.Close()
		jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close jq stdin to signal EOF
	if err := jqStdin.Close(); err != nil {
		return "", fmt.Errorf("failed to close jq stdin: %w", err)
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	result := fmt.Sprintf("Successfully exported SLB information to %s", outputFile)
	return result, nil
}

func main() {
	// Example usage
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		fmt.Println("Example: go run main.go my-slb output.json")
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

