// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create a context with timeout to prevent hanging
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	// Construct the aliyun command with context
	aliyunCmd := exec.CommandContext(ctx, "aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Construct the jq command with context
	jqCmd := exec.CommandContext(ctx, "jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the commands with a pipe
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Set up stderr capture for better error reporting
	aliyunCmd.Stderr = os.Stderr
	jqCmd.Stderr = os.Stderr

