package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate that outputFile is a valid path and not a device or special file
	if outputFile == "" {
		return "", fmt.Errorf("output file cannot be empty")
	}

	// Create the output file securely with proper permissions
	outFile, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the commands with a pipe
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Set up output capture and file writing
	// Use a pipe to capture stdout while also writing to file
	pr, pw, err := os.Pipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for output: %w", err)
	}

	// Tee the output: write to both file and our capture pipe
	jqCmd.Stdout = pw
	jqCmd.Stderr = os.Stderr

	// Start jq command first (it reads from aliyun's stdout)
	if err := jqCmd.Start(); err != nil {
		pw.Close()
		pr.Close()
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command (it writes to jq's stdin)
	if err := aliyunCmd.Start(); err != nil {
		pw.Close()
		pr.Close()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read the output in a goroutine
	outputChan := make(chan []byte, 1)
	errChan := make(chan error, 1)
	go func() {
		var buf [4096]byte
		var result []byte
		for {
			n, err := pr.Read(buf[:])
			if n > 0 {
				// Write to file
				if _, writeErr := outFile.Write(buf[:n]); writeErr != nil {
					errChan <- fmt.Errorf("failed to write to output file: %w", writeErr)
					return
				}
				// Collect for return value
				result = append(result, buf[:n]...)
			}
			if err != nil {
				if err.Error() != "EOF" {
					errChan <- err
				}
				break
			}
		}
		outputChan <- result
		close(outputChan)
	}()

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		pw.Close()
		pr.Close()
		<-outputChan // drain
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the write end of the pipe to signal EOF to jq
	if err := jqCmd.Stdin.(interface{ Close() error }).Close(); err != nil {
		pw.Close()
		pr.Close()
		<-outputChan // drain
		return "", fmt.Errorf("failed to close pipe: %w", err)
	}

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		pw.Close()
		pr.Close()
		<-outputChan // drain
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Close the write end of our capture pipe
	pw.Close()

	// Get the captured output
	var outputBytes []byte
	select {
	case outputBytes = <-outputChan:
	case err := <-errChan:
		pr.Close()
		return "", err
	}
	pr.Close()

	outputStr := string(outputBytes)

	return outputStr, nil
}

