		pipeWriter.Close()
	}()

	// Wait for jq to finish processing
	jqErr := jqCmd.Wait()
	pipeReader.Close()

	// Build result message
	var result strings.Builder
	if aliyunStderr.Len() > 0 {
		result.WriteString(fmt.Sprintf("aliyun stderr: %s\n", aliyunStderr.String()))
	}
	if jqStderr.Len() > 0 {
		result.WriteString(fmt.Sprintf("jq stderr: %s\n", jqStderr.String()))
	}

	// Check for errors
	if jqErr != nil {
		return result.String(), fmt.Errorf("jq command failed: %w", jqErr)
	}

	return strings.TrimSpace(result.String()), nil
}

