	if err != nil {
		return "", fmt.Errorf("failed to read jq output: %w", err)
	}

	// Wait for both commands to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command wait failed: %w", err)
	}

	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	outputStr := string(outputBytes)

	// Write output to file using direct file write instead of shell command
	writeCmd := exec.CommandContext(ctx, "sh", "-c", fmt.Sprintf("cat > '%s'", strings.ReplaceAll(outputFile, "'", "'\\''")))
	writeCmd.Stdin = io.NopCloser(strings.NewReader(outputStr))
	if err := writeCmd.Run(); err != nil {
		return outputStr, fmt.Errorf("failed to write to output file: %w", err)
	}

	return outputStr, nil
}

