package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe to connect aliyun stdout to jq stdin
	stdoutPipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdoutPipe

	// Create pipe to capture jq output
	jqOutputPipe, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read jq output
	jqOutput, err := io.ReadAll(jqOutputPipe)
	if err != nil {
		jqCmd.Wait()
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to read jq output: %w", err)
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		aliyunCmd.Wait()
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	file, err := os.Create(outputFile)
	if err != nil {
		return string(jqOutput), fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	if _, err := file.Write(jqOutput); err != nil {
		return string(jqOutput), fmt.Errorf("failed to write to output file: %w", err)
	}

	return string(jqOutput), nil
}

