// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a file using jq.
// It executes: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the stdout of aliyun command to stdin of jq command
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = pipe

	// Open output file for writing
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set jq command's stdout to the output file
	jqCmd.Stdout = outFile

	// Capture stderr from both commands for error reporting
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get stderr pipe for aliyun command: %w", err)
	}

	jqCmd.Stderr = os.Stderr

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// Try to kill aliyun command if jq fails to start
		_ = aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read stderr from aliyun command asynchronously
	stderrBytes := make([]byte, 4096)
	var aliyunStderrMsg string
	go func() {
		n, _ := aliyunStderr.Read(stderrBytes)
		if n > 0 {
			aliyunStderrMsg = string(stderrBytes[:n])
		}
	}()

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		_ = aliyunCmd.Wait() // Clean up aliyun command
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w (stderr: %s)", err, aliyunStderrMsg)
	}

	result := fmt.Sprintf("Successfully exported SLB information to %s", outputFile)
	return result, nil
}

func main() {
