// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a file.
// It runs: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun output to jq input
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Open output file for writing
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Set jq output to file
	jqCmd.Stdout = file

	// Capture stderr from both commands
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stderr: %w", err)
	}

	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get jq stderr: %w", err)
	}

	// Start jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		_ = jqCmd.Wait() // Clean up jq
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read stderr in goroutines to prevent blocking
	go func() {
		buf := make([]byte, 1024)
		for {
			n, _ := aliyunStderr.Read(buf)
			if n == 0 {
				break
			}
		}
	}()

	go func() {
		buf := make([]byte, 1024)
		for {
			n, _ := jqStderr.Read(buf)
			if n == 0 {
				break
			}
		}
	}()

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		_ = jqCmd.Wait() // Clean up jq
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the pipe to signal EOF to jq
	pipe.Close()

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <load-balancer-name> <output-file>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

