package main

import (
	"fmt"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Command 1: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Command 2: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Command 3: tee <outputFile> (writes to file and passes through to stdout)
	cmd3 := exec.Command("tee", outputFile)

	// Create pipes between commands
	pipe1, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}
	cmd2.Stdin = pipe1

	pipe2, err := cmd2.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for jq command: %w", err)
	}
	cmd3.Stdin = pipe2

	// Get output from tee command
	outputPipe, err := cmd3.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create output pipe: %w", err)
	}

	// Start commands in reverse order (consumers before producers)
	if err := cmd3.Start(); err != nil {
		return "", fmt.Errorf("failed to start tee command: %w", err)
	}
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read all output
	var output []byte
	buf := make([]byte, 4096)
	for {
		n, err := outputPipe.Read(buf)
		if n > 0 {
			output = append(output, buf[:n]...)
		}
		if err != nil {
			break
		}
	}

	// Wait for all commands to complete
	if err := cmd1.Wait(); err != nil {
		return string(output), fmt.Errorf("aliyun command failed: %w", err)
	}
	if err := cmd2.Wait(); err != nil {
		return string(output), fmt.Errorf("jq command failed: %w", err)
	}
	if err := cmd3.Wait(); err != nil {
		return string(output), fmt.Errorf("tee command failed: %w", err)
	}

	return string(output), nil
}

