package main

import (
	"fmt"
	"io"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build command pipeline without shell: aliyun | jq | tee
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	teeCmd := exec.Command("tee", outputFile)

	// Create pipes
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}

	jqCmd.Stdin = aliyunOut

	jqOut, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for jq: %w", err)
	}

	teeCmd.Stdin = jqOut

	// Get output from tee
	teeOut, err := teeCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for tee: %w", err)
	}

	// Start commands in reverse order (consumers first)
	if err := teeCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start tee: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Read all output from tee
	result := make([]byte, 0, 65536)
	buf := make([]byte, 4096)
	for {
		n, err := teeOut.Read(buf)
		if n > 0 {
			result = append(result, buf[:n]...)
		}
		if err == io.EOF {
			break
		}
		if err != nil {
			return string(result), fmt.Errorf("error reading output: %w", err)
		}
	}

	// Wait for all commands
	if err := aliyunCmd.Wait(); err != nil {
		return string(result), fmt.Errorf("aliyun command failed: %w", err)
	}

	if err := jqCmd.Wait(); err != nil {
		return string(result), fmt.Errorf("jq command failed: %w", err)
	}

	if err := teeCmd.Wait(); err != nil {
		return string(result), fmt.Errorf("tee command failed: %w", err)
	}

	return string(result), nil
}

