package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a file using jq.
// It executes: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the commands with a pipe
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Set output of jq command to the file
	jqCmd.Stdout = outFile
	jqCmd.Stderr = os.Stderr

	// Start the jq command first (it will wait for input from the pipe)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		// Kill jq command if aliyun fails
		jqCmd.Process.Kill()
		jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the write end of the pipe by setting stdin to nil and letting jq finish
	// Actually, we need to close the pipe explicitly - but StdoutPipe does this automatically when process exits

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

